/**
 * Provides a utility function to determine whether a graphic's origin is a [WFSGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/WFSGraphicOrigin/).
 *
 * @since 5.0
 * @example
 * // Use hitTest() to get a graphic, then check whether it originated from a WFSLayer.
 * view.hitTest(screenPoint).then((response) => {
 *   const graphic = response.results[0]?.graphic;
 *   if (!graphic) {
 *     return;
 *   }
 *   if (isWFSGraphicOrigin(graphic.origin)) {
 *     // hitTest returned a graphic from a WFSLayer.
 *     // Use this info for your processing logic.
 *   } else {
 *     console.log("graphic's origin is NOT a WFSLayer");
 *   }
 * });
 */
import type GraphicOrigin from "./GraphicOrigin.js";
import type WFSGraphicOrigin from "./WFSGraphicOrigin.js";

/**
 * Utility function that determines whether a graphic’s origin is a [WFSGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/WFSGraphicOrigin/).
 *
 * @param origin - The graphic origin to check.
 * @returns Returns `true` if the graphic origin is of type [WFSGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/WFSGraphicOrigin/), `false` otherwise.
 */
export function isWFSGraphicOrigin(origin: GraphicOrigin | null | undefined): origin is WFSGraphicOrigin;